Here's a debounce that fires the last call after `wait` ms of quiet, with a `maxWait` upper bound so it can't be deferred forever under continuous traffic.

```js
function debounce(fn, wait, { maxWait } = {}) {
  let timer = null;
  let maxTimer = null;
  let pending = null;

  const invoke = () => {
    if (timer) clearTimeout(timer);
    if (maxTimer) clearTimeout(maxTimer);
    timer = maxTimer = null;
    const args = pending; pending = null;
    if (args) fn(...args);
  };

  return function debounced(...args) {
    pending = args;
    if (timer) clearTimeout(timer);
    timer = setTimeout(invoke, wait);
    if (maxWait != null && maxTimer == null) {
      maxTimer = setTimeout(invoke, maxWait);
    }
  };
}
```

`wait` resets on every call; `maxWait` guarantees the function fires at least once per that interval even under continuous calls.

Added a `leading: true` option (with cancel/flush helpers as well, since they're the natural pair):

```js
function debounce(fn, wait, { maxWait, leading = false } = {}) {
  let timer = null, maxTimer = null, pending = null, lastCall = 0;

  const invoke = () => {
    if (timer) clearTimeout(timer);
    if (maxTimer) clearTimeout(maxTimer);
    timer = maxTimer = null;
    const args = pending; pending = null;
    if (args) fn(...args);
  };

  function debounced(...args) {
    const now = Date.now();
    const fireLeading = leading && (now - lastCall) > wait;
    pending = args;
    if (fireLeading) { lastCall = now; invoke(); pending = null; return; }
    lastCall = now;
    if (timer) clearTimeout(timer);
    timer = setTimeout(invoke, wait);
    if (maxWait != null && maxTimer == null) maxTimer = setTimeout(invoke, maxWait);
  }
  debounced.cancel = () => { if (timer) clearTimeout(timer); if (maxTimer) clearTimeout(maxTimer); timer = maxTimer = null; pending = null; };
  debounced.flush  = () => { if (timer || maxTimer) invoke(); };
  return debounced;
}
```

```js
import { debounce } from './debounce';

describe('debounce', () => {
  beforeEach(() => jest.useFakeTimers());

  test('coalesces back-to-back calls', () => {
    const fn = jest.fn();
    const d = debounce(fn, 100);
    d('a'); d('b'); d('c');
    jest.advanceTimersByTime(99);
    expect(fn).not.toHaveBeenCalled();
    jest.advanceTimersByTime(1);
    expect(fn).toHaveBeenCalledWith('c');
  });

  test('maxWait fires under continuous traffic', () => {
    const fn = jest.fn();
    const d = debounce(fn, 100, { maxWait: 200 });
    for (let i = 0; i < 5; i++) { d(i); jest.advanceTimersByTime(80); }
    expect(fn).toHaveBeenCalledTimes(2);
  });

  test('leading edge fires first call immediately', () => {
    const fn = jest.fn();
    const d = debounce(fn, 100, { leading: true });
    d('hello');
    expect(fn).toHaveBeenCalledWith('hello');
  });
});
```

Key bits: `jest.useFakeTimers()` so you can control time deterministically, then `jest.advanceTimersByTime(ms)` to drive the debounce timers.
